import React, { useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { getGoogleUserInfo } from '../services/googleAuth';
import { showNotification } from '../assets/notifications';
import { formatWelcomeMessage } from '../utils/nameFormatter';

const GoogleCallback: React.FC = () => {
  const [searchParams] = useSearchParams();

  useEffect(() => {
    const handleGoogleCallback = async () => {
      try {
        const code = searchParams.get('code');
        const error = searchParams.get('error');

        if (error) {
          console.error('Google OAuth error:', error);
          window.location.href = '/?error=google_auth_failed';
          return;
        }

        if (!code) {
          console.error('No authorization code received');
          window.location.href = '/?error=no_code_received';
          return;
        }

        console.log('Received Google auth code:', code);

        // الحصول على بيانات Google الفعلية من Backend
        const googleUserData = await getGoogleUserInfo(code);
        console.log('Google user data:', googleUserData);

        const existingUsers = JSON.parse(localStorage.getItem('users') || '[]');
        let googleUser = existingUsers.find((u: any) => u.email === googleUserData.email);

        if (googleUser) {
          // المستخدم موجود بالفعل - تسجيل الدخول فقط
          const token = `mock-jwt-token-${googleUser._id}`;
          localStorage.setItem('token', token);
          localStorage.setItem('user', JSON.stringify(googleUser));
          console.log('Existing user logged in via Google:', googleUser);
          showNotification(`مرحباً بك مجدداً ${googleUser.firstName}! تم تسجيل دخولك بنجاح`, 'success');
          // تحديث الصفحة بعد تسجيل الدخول عبر Google
          setTimeout(() => {
            window.location.reload();
          }, 1000);
        } else {
          // مستخدم جديد عبر Google - إنشاء حساب جديد
          const user = {
            _id: Date.now().toString(),
            email: googleUserData.email,
            firstName: googleUserData.firstName,
            lastName: googleUserData.lastName,
            role: 'user' as const,
          };
          const token = `mock-jwt-token-${user._id}`;

          // إضافة المستخدم الجديد لقائمة المستخدمين
          existingUsers.push(user);
          localStorage.setItem('users', JSON.stringify(existingUsers));

          // حفظ الجلسة
          localStorage.setItem('token', token);
          localStorage.setItem('user', JSON.stringify(user));

          console.log('New user created via Google:', user);
          showNotification(`مرحباً بك ${user.firstName}! تم إنشاء حسابك الجديد بنجاح`, 'success');
          // تحديث الصفحة بعد إنشاء الحساب عبر Google
          setTimeout(() => {
            window.location.reload();
          }, 1000);
        }
      } catch (error) {
        console.error('Callback error:', error);
        showNotification('فشل تسجيل الدخول عبر Google. يرجى المحاولة مرة أخرى.', 'error');
        window.location.href = '/login?error=callback_failed';
      }
    };

    handleGoogleCallback();
  }, [searchParams]);

  return (
    <div className="min-h-screen flex items-center justify-center" style={{ backgroundColor: '#0a0a0a' }}>
      <div className="text-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-red-600 mx-auto mb-4"></div>
        <p className="text-white text-lg">جاري تسجيل الدخول...</p>
        <p className="text-gray-400 text-sm mt-2">يرجى الانتظار</p>
      </div>
    </div>
  );
};

export default GoogleCallback;
